BEGIN;
ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS is_active boolean DEFAULT true;
ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS is_approved boolean;
ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS deleted_at timestamptz DEFAULT NULL;
ALTER TABLE public.profiles ALTER COLUMN is_approved SET DEFAULT false;
UPDATE public.profiles SET is_approved = true WHERE is_approved IS NULL AND deleted_at IS NULL;
CREATE TABLE IF NOT EXISTS public.super_admins (user_id uuid PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE, created_at timestamptz DEFAULT now());
ALTER TABLE public.super_admins ENABLE ROW LEVEL SECURITY;
CREATE OR REPLACE FUNCTION public.is_approved_active_user() RETURNS boolean LANGUAGE sql SECURITY DEFINER SET search_path = public STABLE AS $$ SELECT EXISTS (SELECT 1 FROM public.profiles p WHERE p.id = auth.uid() AND COALESCE(p.is_active, false) = true AND COALESCE(p.is_approved, false) = true AND p.deleted_at IS NULL); $$;
CREATE OR REPLACE FUNCTION public.is_admin() RETURNS boolean LANGUAGE sql SECURITY DEFINER SET search_path = public STABLE AS $$ SELECT (EXISTS (SELECT 1 FROM public.super_admins sa WHERE sa.user_id = auth.uid()) OR EXISTS (SELECT 1 FROM public.profiles p WHERE p.id = auth.uid() AND p.role = 'admin' AND COALESCE(p.is_active, false) = true AND COALESCE(p.is_approved, false) = true AND p.deleted_at IS NULL)); $$;
CREATE OR REPLACE FUNCTION public.is_manager() RETURNS boolean LANGUAGE sql SECURITY DEFINER SET search_path = public STABLE AS $$ SELECT (public.is_admin() OR EXISTS (SELECT 1 FROM public.profiles p WHERE p.id = auth.uid() AND p.role = 'manager' AND COALESCE(p.is_active, false) = true AND COALESCE(p.is_approved, false) = true AND p.deleted_at IS NULL)); $$;
CREATE OR REPLACE FUNCTION public.check_is_admin() RETURNS boolean LANGUAGE sql SECURITY DEFINER SET search_path = public STABLE AS $$ SELECT public.is_admin(); $$;
CREATE OR REPLACE FUNCTION public.can_edit_delivery_plan() RETURNS boolean LANGUAGE sql SECURITY DEFINER SET search_path = public STABLE AS $$ SELECT (public.is_admin() OR EXISTS (SELECT 1 FROM public.profiles p WHERE p.id = auth.uid() AND p.department = 'sales' AND COALESCE(p.is_active, false) = true AND COALESCE(p.is_approved, false) = true AND p.deleted_at IS NULL)); $$;
CREATE OR REPLACE FUNCTION public.require_approved_active_user() RETURNS void LANGUAGE plpgsql SECURITY DEFINER SET search_path = public STABLE AS $$ BEGIN IF NOT public.is_approved_active_user() THEN RAISE EXCEPTION 'Tai khoan chua duoc duyet hoac da bi khoa.'; END IF; END; $$;
GRANT EXECUTE ON FUNCTION public.is_approved_active_user() TO authenticated;
GRANT EXECUTE ON FUNCTION public.is_admin() TO authenticated;
GRANT EXECUTE ON FUNCTION public.is_manager() TO authenticated;
GRANT EXECUTE ON FUNCTION public.check_is_admin() TO authenticated;
GRANT EXECUTE ON FUNCTION public.can_edit_delivery_plan() TO authenticated;
GRANT EXECUTE ON FUNCTION public.require_approved_active_user() TO authenticated;
DO $do$ DECLARE t record; r record; BEGIN FOR t IN SELECT * FROM (VALUES ('profiles'), ('customers'), ('products'), ('inventory_transactions'), ('inventory_opening_balances'), ('delivery_plans'), ('shipment_logs'), ('selling_entities'), ('system_settings'), ('inventory_stocktakes'), ('inventory_stocktake_lines'), ('inventory_report_closures'), ('inventory_report_closure_lines'), ('phoi_transactions'), ('returned_goods_records'), ('vehicles')) AS v(table_name) LOOP IF to_regclass('public.' || t.table_name) IS NOT NULL THEN EXECUTE format('ALTER TABLE public.%I ENABLE ROW LEVEL SECURITY', t.table_name); FOR r IN SELECT policyname FROM pg_policies WHERE schemaname = 'public' AND tablename = t.table_name LOOP EXECUTE format('DROP POLICY IF EXISTS %I ON public.%I', r.policyname, t.table_name); END LOOP; END IF; END LOOP; END $do$;
