DO $do$ BEGIN IF to_regprocedure('public.inventory_calculate_product_stock_v1_unsafe_20260710(text,text,text)') IS NULL AND to_regprocedure('public.inventory_calculate_product_stock_v1(text,text,text)') IS NOT NULL THEN ALTER FUNCTION public.inventory_calculate_product_stock_v1(text,text,text) RENAME TO inventory_calculate_product_stock_v1_unsafe_20260710; END IF; IF to_regprocedure('public.sales_command_center_report_v2_unsafe_20260710(date,date,date,date)') IS NULL AND to_regprocedure('public.sales_command_center_report_v2(date,date,date,date)') IS NOT NULL THEN ALTER FUNCTION public.sales_command_center_report_v2(date,date,date,date) RENAME TO sales_command_center_report_v2_unsafe_20260710; END IF; END $do$;
CREATE OR REPLACE FUNCTION public.inventory_calculate_product_stock_v1(p_baseline_date text, p_movements_start_date text, p_movements_end_date text) RETURNS TABLE (product_id uuid, opening_qty numeric, inbound_qty numeric, outbound_qty numeric, current_qty numeric) LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$ BEGIN PERFORM public.require_approved_active_user(); RETURN QUERY SELECT x.product_id, x.opening_qty, x.inbound_qty, x.outbound_qty, x.current_qty FROM public.inventory_calculate_product_stock_v1_unsafe_20260710(p_baseline_date, p_movements_start_date, p_movements_end_date) x; END; $$;
CREATE OR REPLACE FUNCTION public.sales_command_center_report_v2(p1_start date, p1_end date, p2_start date, p2_end date) RETURNS jsonb LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$ BEGIN PERFORM public.require_approved_active_user(); RETURN public.sales_command_center_report_v2_unsafe_20260710(p1_start, p1_end, p2_start, p2_end); END; $$;
DO $do$ DECLARE f regprocedure; BEGIN FOR f IN SELECT unnest(ARRAY[to_regprocedure('public.inventory_calculate_product_stock_v1_unsafe_20260710(text,text,text)'), to_regprocedure('public.sales_command_center_report_v2_unsafe_20260710(date,date,date,date)')]) LOOP IF f IS NOT NULL THEN EXECUTE format('REVOKE ALL ON FUNCTION %s FROM PUBLIC, anon, authenticated', f); END IF; END LOOP; END $do$;
GRANT EXECUTE ON FUNCTION public.inventory_calculate_product_stock_v1(text, text, text) TO authenticated;
GRANT EXECUTE ON FUNCTION public.sales_command_center_report_v2(date, date, date, date) TO authenticated;
DO $do$ DECLARE f regprocedure; BEGIN FOR f IN SELECT unnest(ARRAY[to_regprocedure('public.is_approved_active_user()'), to_regprocedure('public.is_admin()'), to_regprocedure('public.is_manager()'), to_regprocedure('public.check_is_admin()'), to_regprocedure('public.can_edit_delivery_plan()'), to_regprocedure('public.require_approved_active_user()'), to_regprocedure('public.inventory_calculate_product_stock_v1(text,text,text)'), to_regprocedure('public.sales_command_center_report_v2(date,date,date,date)'), to_regprocedure('public.inventory_get_last_tx_dates()')]) LOOP IF f IS NOT NULL THEN EXECUTE format('REVOKE ALL ON FUNCTION %s FROM PUBLIC, anon', f); EXECUTE format('GRANT EXECUTE ON FUNCTION %s TO authenticated', f); END IF; END LOOP; END $do$;
